package com.example.loggingapi.controller;

import com.example.loggingapi.model.ApiResponse;
import com.example.loggingapi.model.HealthResponse;
import com.example.loggingapi.model.MessageRequest;
import com.example.loggingapi.service.LoggingService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/v1")
class ProductionLoggingController {

    private static final Logger logger = LoggerFactory.getLogger(ProductionLoggingController.class);
    private final LoggingService loggingService;

    ProductionLoggingController(LoggingService loggingService) {
        this.loggingService = loggingService;
    }

    @GetMapping("/health")
    public ResponseEntity<HealthResponse> getHealth() {
        logger.info("Processing health endpoint");
        HealthResponse response = new HealthResponse("UP", "Production API service is running");
        logger.info("Health endpoint processed successfully");
        return ResponseEntity.ok(response);
    }

    @GetMapping("/hello")
    public ResponseEntity<ApiResponse> getHello(@RequestParam(defaultValue = "World") String name) {
        logger.info("Processing hello endpoint");
        ApiResponse response = loggingService.buildGreeting(name);
        logger.info("Hello endpoint processed successfully");
        return ResponseEntity.ok(response);
    }

    @PostMapping("/echo")
    public ResponseEntity<ApiResponse> echo(@RequestBody MessageRequest request) {
        logger.info("Processing echo endpoint");
        ApiResponse response = new ApiResponse("Echo: " + request.getMessage());
        logger.info("Echo endpoint processed successfully");
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }
}

